# dbt transform Job (#609) — self-hosted dbt Core on the shared dataq-cae. Runs
# `dbt build` over the retail lineage models (dbt/, staging views + mart dynamic
# tables on Snowflake), then publishes manifest.json + run_results.json to ADLS.
# Same ACA-Job shape as the mockdata feeds (mockdata_job.tf); a Container Apps Job
# (not a Container App) because dbt is a run-to-completion batch, not a service.
#
# Auth mirrors the Airflow container (airflow.tf): Snowflake password from Key Vault,
# ADLS write via the storage account connection string. Runs as DATAQ_LOADER (not
# ACCOUNTADMIN) — see profiles.yml / snowflake.tf loader_create_schema.
#
# Runs on var.dbt_cron; also startable on demand:  az containerapp job start -n dbt-lineage -g dataq-rg
#
# NOTE: build + push the image before the first run:
#   az acr login -n <registry>
#   docker build -t <login_server>/dbt-lineage:latest dbt/ && docker push <login_server>/dbt-lineage:latest
# Post-wind-down the same image runs as a docker-compose service (dbt/README.md).

resource "azurerm_container_app_job" "dbt_lineage" {
  name                         = "dbt-lineage"
  container_app_environment_id = azurerm_container_app_environment.harness.id
  resource_group_name          = data.azurerm_resource_group.dataq.name
  location                     = var.azure_location

  # dbt build + dynamic-table initial refresh can take a few minutes; no retry (a
  # failed run_results.json is itself the signal the #611 provider observes).
  replica_timeout_in_seconds = 1800
  replica_retry_limit        = 0

  schedule_trigger_config {
    cron_expression          = var.dbt_cron
    parallelism              = 1
    replica_completion_count = 1
  }

  registry {
    server               = azurerm_container_registry.harness.login_server
    username             = azurerm_container_registry.harness.admin_username
    password_secret_name = "acr-password"
  }

  secret {
    name  = "acr-password"
    value = azurerm_container_registry.harness.admin_password
  }
  secret {
    name  = "snowflake-password"
    value = data.azurerm_key_vault_secret.snowflake_password.value
  }
  secret {
    name  = "storage-conn"
    value = azurerm_storage_account.landing.primary_connection_string
  }

  template {
    container {
      name    = "dbt-lineage"
      image   = "${azurerm_container_registry.harness.login_server}/dbt-lineage:${var.dbt_image_tag}"
      cpu     = 0.5
      memory  = "1Gi"
      command = ["/app/dbt/run.sh"]
      args    = ["build"]

      env {
        name  = "SNOWFLAKE_ACCOUNT"
        value = "${var.snowflake_organization_name}-${var.snowflake_account_name}"
      }
      env {
        name  = "SNOWFLAKE_USER"
        value = var.snowflake_reader_user
      }
      env {
        name        = "SNOWFLAKE_PASSWORD"
        secret_name = "snowflake-password"
      }
      env {
        name  = "SNOWFLAKE_WAREHOUSE"
        value = var.snowflake_warehouse
      }
      env {
        name  = "SNOWFLAKE_DATABASE"
        value = var.snowflake_database
      }
      # Least-privilege: dbt builds as DATAQ_LOADER, never ACCOUNTADMIN.
      env {
        name  = "DBT_SNOWFLAKE_ROLE"
        value = var.snowflake_loader_role
      }
      # Artifact publish target (upload_artifacts.py) — the "raw" filesystem.
      env {
        name  = "DBT_ARTIFACTS_URI"
        value = "adls://${azurerm_storage_account.landing.name}/${var.adls_filesystems[1]}/dbt"
      }
      env {
        name        = "AZURE_STORAGE_CONNECTION_STRING"
        secret_name = "storage-conn"
      }
    }
  }

  tags = local.common_tags
}

